-- ============================================================\n-- LogiX 数据库索引优化脚本\n-- LogiX Database Index Optimization Script\n-- ============================================================\n-- 用途: 添加缺失的索引，优化查询性能\n-- Usage: Add missing indexes to optimize query performance\n-- ============================================================\n\n-- ============================================================\n-- 业务表索引优化\n-- ============================================================\n\n-- biz_containers 表索引优化\n-- 增加对常用查询字段的索引\nCREATE INDEX IF NOT EXISTS idx_containers_seal ON biz_containers(seal_number);\nCREATE INDEX IF NOT EXISTS idx_containers_weight ON biz_containers(gross_weight);\nCREATE INDEX IF NOT EXISTS idx_containers_cbm ON biz_containers(cbm);\n\n-- biz_replenishment_orders 表索引优化\n-- 增加对销售国家和订单日期的索引\nCREATE INDEX IF NOT EXISTS idx_replenishment_country ON biz_replenishment_orders(sell_to_country);\nCREATE INDEX IF NOT EXISTS idx_replenishment_expected_ship ON biz_replenishment_orders(expected_ship_date);\n\n-- ============================================================\n-- 流程表索引优化\n-- ============================================================\n\n-- process_sea_freight 表索引优化\n-- 增加对常用查询字段的索引\nCREATE INDEX IF NOT EXISTS idx_sea_freight_eta ON process_sea_freight(eta);\nCREATE INDEX IF NOT EXISTS idx_sea_freight_ata ON process_sea_freight(ata);\nCREATE INDEX IF NOT EXISTS idx_sea_freight_port_loading ON process_sea_freight(port_of_loading);\nCREATE INDEX IF NOT EXISTS idx_sea_freight_port_discharge ON process_sea_freight(port_of_discharge);\nCREATE INDEX IF NOT EXISTS idx_sea_freight_booking ON process_sea_freight(booking_number);\n\n-- process_port_operations 表索引优化\n-- 增加对日期字段和状态字段的索引\nCREATE INDEX IF NOT EXISTS idx_port_operations_eta ON process_port_operations(eta_dest_port);\nCREATE INDEX IF NOT EXISTS idx_port_operations_ata ON process_port_operations(ata_dest_port);\nCREATE INDEX IF NOT EXISTS idx_port_operations_last_free ON process_port_operations(last_free_date);\nCREATE INDEX IF NOT EXISTS idx_port_operations_customs ON process_port_operations(customs_status);\nCREATE INDEX IF NOT EXISTS idx_port_operations_isf ON process_port_operations(isf_status);\nCREATE INDEX IF NOT EXISTS idx_port_operations_status_code ON process_port_operations(status_code);\n\n-- process_trucking_transport 表索引优化\n-- 增加对日期字段和状态字段的索引\nCREATE INDEX IF NOT EXISTS idx_trucking_pickup ON process_trucking_transport(pickup_date);\nCREATE INDEX IF NOT EXISTS idx_trucking_delivery ON process_trucking_transport(delivery_date);\nCREATE INDEX IF NOT EXISTS idx_trucking_last_pickup ON process_trucking_transport(last_pickup_date);\nCREATE INDEX IF NOT EXISTS idx_trucking_planned_pickup ON process_trucking_transport(planned_pickup_date);\nCREATE INDEX IF NOT EXISTS idx_trucking_company ON process_trucking_transport(trucking_company_id);\nCREATE INDEX IF NOT EXISTS idx_trucking_status ON process_trucking_transport(schedule_status);\n\n-- process_warehouse_operations 表索引优化\n-- 增加对日期字段和状态字段的索引\nCREATE INDEX IF NOT EXISTS idx_warehouse_arrival ON process_warehouse_operations(warehouse_arrival_date);\nCREATE INDEX IF NOT EXISTS idx_warehouse_unload ON process_warehouse_operations(unload_date);\nCREATE INDEX IF NOT EXISTS idx_warehouse_planned_unload ON process_warehouse_operations(planned_unload_date);\nCREATE INDEX IF NOT EXISTS idx_warehouse_last_unload ON process_warehouse_operations(last_unload_date);\nCREATE INDEX IF NOT EXISTS idx_warehouse_wms_status ON process_warehouse_operations(wms_status);\nCREATE INDEX IF NOT EXISTS idx_warehouse_ebs_status ON process_warehouse_operations(ebs_status);\n\n-- process_empty_return 表索引优化\n-- 增加对日期字段的索引\nCREATE INDEX IF NOT EXISTS idx_empty_return_last ON process_empty_return(last_return_date);\nCREATE INDEX IF NOT EXISTS idx_empty_return_planned ON process_empty_return(planned_return_date);\nCREATE INDEX IF NOT EXISTS idx_empty_return_actual ON process_empty_return(return_time);\n\n-- ============================================================\n-- 扩展表索引优化\n-- ============================================================\n\n-- ext_container_status_events 表索引优化\n-- 增加对状态代码和数据源的索引\nCREATE INDEX IF NOT EXISTS idx_status_events_status ON ext_container_status_events(status_code);\nCREATE INDEX IF NOT EXISTS idx_status_events_source ON ext_container_status_events(data_source);\n\n-- ext_container_loading_records 表索引优化\n-- 增加对港口和日期的索引\nCREATE INDEX IF NOT EXISTS idx_loading_loading_port ON ext_container_loading_records(loading_port);\nCREATE INDEX IF NOT EXISTS idx_loading_discharge_port ON ext_container_loading_records(discharge_port);\nCREATE INDEX IF NOT EXISTS idx_loading_date ON ext_container_loading_records(loading_date);\nCREATE INDEX IF NOT EXISTS idx_loading_discharge_date ON ext_container_loading_records(discharge_date);\n\n-- ext_container_hold_records 表索引优化\n-- 增加对类型、状态和日期的索引\nCREATE INDEX IF NOT EXISTS idx_hold_type ON ext_container_hold_records(hold_type);\nCREATE INDEX IF NOT EXISTS idx_hold_status ON ext_container_hold_records(status);\nCREATE INDEX IF NOT EXISTS idx_hold_date ON ext_container_hold_records(hold_date);\nCREATE INDEX IF NOT EXISTS idx_hold_release_date ON ext_container_hold_records(release_date);\n\n-- ext_container_charges 表索引优化\n-- 增加对日期和状态的索引\nCREATE INDEX IF NOT EXISTS idx_charges_date ON ext_container_charges(charge_date);\nCREATE INDEX IF NOT EXISTS idx_charges_status ON ext_container_charges(status);\n\n-- ============================================================\n-- 映射表索引优化\n-- ============================================================\n\n-- dict_port_warehouse_mapping 表索引优化\n-- 增加组合索引\nCREATE INDEX IF NOT EXISTS idx_port_warehouse_combined ON dict_port_warehouse_mapping(port_code, warehouse_code, is_active);\n\n-- dict_warehouse_trucking_mapping 表索引优化\n-- 增加组合索引\nCREATE INDEX IF NOT EXISTS idx_warehouse_trucking_combined ON dict_warehouse_trucking_mapping(country, warehouse_code, trucking_company_id, is_active);\n\n-- dict_trucking_port_mapping 表索引优化\n-- 增加组合索引\nCREATE INDEX IF NOT EXISTS idx_trucking_port_combined ON dict_trucking_port_mapping(country, trucking_company_id, port_code, is_active);\n\n-- ============================================================\n-- 字典表索引优化\n-- ============================================================\n\n-- dict_ports 表索引优化\n-- 增加对港口类型和状态的索引\nCREATE INDEX IF NOT EXISTS idx_ports_type ON dict_ports(port_type);\nCREATE INDEX IF NOT EXISTS idx_ports_status ON dict_ports(status);\n\n-- dict_shipping_companies 表索引优化\n-- 增加对状态的索引\nCREATE INDEX IF NOT EXISTS idx_shipping_status ON dict_shipping_companies(status);\n\n-- dict_freight_forwarders 表索引优化\n-- 增加对状态的索引\nCREATE INDEX IF NOT EXISTS idx_forwarders_status ON dict_freight_forwarders(status);\n\n-- dict_customs_brokers 表索引优化\n-- 增加对状态的索引\nCREATE INDEX IF NOT EXISTS idx_brokers_status ON dict_customs_brokers(status);\n\n-- dict_trucking_companies 表索引优化\n-- 增加对状态和日容量的索引\nCREATE INDEX IF NOT EXISTS idx_trucking_status ON dict_trucking_companies(status);\nCREATE INDEX IF NOT EXISTS idx_trucking_capacity ON dict_trucking_companies(daily_capacity);\n\n-- dict_overseas_companies 表索引优化\n-- 增加对国家和状态的索引\nCREATE INDEX IF NOT EXISTS idx_overseas_country ON dict_overseas_companies(country);\nCREATE INDEX IF NOT EXISTS idx_overseas_status ON dict_overseas_companies(is_active);\n\n-- ============================================================\n-- 完成索引优化\n-- ============================================================\n\n-- 查看所有索引\nSELECT \n    schemaname, \n    tablename, \n    indexname, \n    indexdef \nFROM \n    pg_indexes \nWHERE \n    schemaname = 'public' \nORDER BY \n    tablename, \n    indexname;\n\n-- 查看表大小和索引大小\nSELECT \n    table_name, \n    pg_size_pretty(pg_total_relation_size(table_name)) AS total_size, \n    pg_size_pretty(pg_indexes_size(table_name)) AS index_size \nFROM \n    information_schema.tables \nWHERE \n    table_schema = 'public' \n    AND table_type = 'BASE TABLE' \nORDER BY \n    pg_total_relation_size(table_name) DESC;\n